import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AdminSetting } from '../../core/models';

interface ServiceGroup {
  service: string;
  label: string;
  blurb: string;
  settings: AdminSetting[];
}

/**
 * Admin settings (admin only) — backing service credentials (postgresql +
 * minio) grouped by service with configured / unconfigured badges and a
 * per-service credential form. Values arrive masked from the API. `settings` is
 * a `signal<AdminSetting[]>` mock per the data contract — service_agent wires
 * getSettings / updateSettings (masked-value handling).
 */
@Component({
  selector: 'app-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.css',
})
export class SettingsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly savedFor = signal<string | null>(null);

  readonly settings = signal<AdminSetting[]>([
    { key: 'POSTGRESQL_URL', service: 'postgresql', label: 'Connection URL', value: '••••••••', configured: true },
    { key: 'POSTGRESQL_POOL_MAX', service: 'postgresql', label: 'Max pool size', value: '10', configured: true },
    { key: 'MINIO_ENDPOINT', service: 'minio', label: 'Endpoint', value: '', configured: false },
    { key: 'MINIO_ACCESS_KEY', service: 'minio', label: 'Access key', value: '', configured: false },
    { key: 'MINIO_SECRET_KEY', service: 'minio', label: 'Secret key', value: '', configured: false },
  ]);

  // Local edit buffer keyed by setting key.
  edits: Record<string, string> = {};

  readonly groups = signal<ServiceGroup[]>([]);

  ngOnInit(): void {
    // service_agent: this.settings.set(await ApiService.getSettings()).
    this.rebuild();
  }

  private rebuild(): void {
    const meta: Record<string, { label: string; blurb: string }> = {
      postgresql: { label: 'PostgreSQL', blurb: 'Primary database connection.' },
      minio: { label: 'MinIO (object storage)', blurb: 'S3-compatible object storage backend.' },
    };
    const byService = new Map<string, AdminSetting[]>();
    for (const s of this.settings()) {
      const arr = byService.get(s.service) ?? [];
      arr.push(s);
      byService.set(s.service, arr);
    }
    this.groups.set(
      [...byService.entries()].map(([service, settings]) => ({
        service,
        label: meta[service]?.label ?? service,
        blurb: meta[service]?.blurb ?? '',
        settings,
      })),
    );
  }

  isConfigured(group: ServiceGroup): boolean {
    return group.settings.length > 0 && group.settings.every((s) => s.configured);
  }

  save(group: ServiceGroup): void {
    this.error.set(null);
    // service_agent: build a { key: value } map from this.edits and call
    // ApiService.updateSettings(); only send changed (non-masked) values.
    this.settings.update((list) =>
      list.map((s) =>
        s.service === group.service && this.edits[s.key]
          ? { ...s, value: '••••••••', configured: true }
          : s,
      ),
    );
    this.edits = {};
    this.rebuild();
    this.savedFor.set(group.service);
  }
}
